"use client";

import { useState } from "react";
import { motion } from "framer-motion";

export default function Home() {
  const [formData, setFormData] = useState({
    amount: "",
    loanFor: "individual",
    employmentStatus: "employed",
    collateral: "collateral-free",
    approval: "normal",
    duration: "",
  });
  const [response, setResponse] = useState("");
  const [loading, setLoading] = useState(false);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setResponse("");

    try {
      const res = await fetch("/api/loan-search", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(formData),
      });

      const data = await res.json();
      setResponse(data.data);
    } catch (error) {
      setResponse("Error fetching loan information.");
    }

    setLoading(false);
  };

  return (
    <div className="min-h-screen flex flex-col justify-center items-center p-8">
      <header className="mb-12 text-center">
        <h1 className="text-5xl font-bold mb-4">
          Welcome to{" "}
          <motion.span
            className="text-blue-600 dark:text-blue-400"
            animate={{ color: ["#2563eb", "#f59e0b", "#2563eb"] }}
            transition={{ duration: 2, repeat: Infinity, ease: "easeInOut" }}
          >
            LoanAI
          </motion.span>
        </h1>
        <p className="text-xl">Find the best loan and credit facility providers.</p>
      </header>

      {/* Loan Search Form */}
      <div className="w-full max-w-lg bg-white dark:bg-gray-800 p-6 rounded-lg shadow-md text-center">
        <h2 className="text-lg font-semibold text-blue-600">Search for Loans</h2>
        <form onSubmit={handleSearch} className="mt-4 flex flex-col gap-4">
          <input
            type="number"
            name="amount"
            placeholder="Loan Amount"
            value={formData.amount}
            onChange={handleChange}
            className="p-3 border rounded-md bg-gray-100 dark:bg-gray-700 dark:text-white w-full"
            required
          />

          <select name="loanFor" value={formData.loanFor} onChange={handleChange} className="p-3 border rounded-md bg-gray-100 dark:bg-gray-700 dark:text-white w-full">
            <option value="individual">Individual</option>
            <option value="business">Business</option>
          </select>

          <select name="employmentStatus" value={formData.employmentStatus} onChange={handleChange} className="p-3 border rounded-md bg-gray-100 dark:bg-gray-700 dark:text-white w-full">
            <option value="employed">Employed</option>
            <option value="entrepreneur">Entrepreneur</option>
          </select>

          <select name="collateral" value={formData.collateral} onChange={handleChange} className="p-3 border rounded-md bg-gray-100 dark:bg-gray-700 dark:text-white w-full">
            <option value="collateral">Collateral Loans</option>
            <option value="collateral-free">Collateral Free Loans</option>
          </select>

          <select name="approval" value={formData.approval} onChange={handleChange} className="p-3 border rounded-md bg-gray-100 dark:bg-gray-700 dark:text-white w-full">
            <option value="instant">Instant</option>
            <option value="normal">Normal</option>
          </select>

          <input
            type="number"
            name="duration"
            placeholder="Loan Duration (in months)"
            value={formData.duration}
            onChange={handleChange}
            className="p-3 border rounded-md bg-gray-100 dark:bg-gray-700 dark:text-white w-full"
            required
          />

          <button
            type="submit"
            className="px-6 py-3 bg-blue-600 text-white rounded-md shadow hover:bg-blue-700 transition-colors"
            disabled={loading}
          >
            {loading ? "Searching..." : "Find Loans"}
          </button>
        </form>

        {response && (
          <div className="mt-6 bg-gray-100 dark:bg-gray-700 p-4 rounded-lg shadow">
            <h3 className="text-md font-semibold text-blue-600">Results:</h3>
            <p className="mt-2 text-gray-800 dark:text-gray-300">{response}</p>
          </div>
        )}
      </div>
    </div>
  );
}
